mapper.select:
SELECT user_id, available, escrow, version
  FROM credit_balance
 WHERE user_id = #{userId}

mapper.update:
UPDATE credit_balance
   SET available = available - #{amount},
       escrow    = escrow + #{amount},
       version   = version + 1
 WHERE user_id = #{userId}
   AND available >= #{amount}

UPDATE credit_balance
   SET escrow  = escrow - #{amount},
       version = version + 1
 WHERE user_id = #{userId}
   AND escrow >= #{amount}

UPDATE credit_balance
   SET escrow    = escrow - #{amount},
       available = available + #{amount},
       version   = version + 1
 WHERE user_id = #{userId}
   AND escrow >= #{amount}

mapper.select:
SELECT COUNT(1)
  FROM credit_ledger
 WHERE reason = #{reason}
   AND ref_id = #{refId}
